        "university_degree": cell("syria > privately sponsored refugees", education_row + "> has a university degree")
    }

    # Compare the levels of education for government-assisted and privately sponsored refugees
    if syria_gar["does_not_have_high_school_diploma"] < syria_ps["does_not_have_high_school_diploma"]:
        result = "government-assisted refugees"
    else:
